describe('Register integration', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockAuth = {
      isAuthenticated: false,
      register: mockRegister,
    };
  });

  afterEach(() => {
    cleanup();
  });

  it('shows password tips and blocks submit on invalid fields', async () => {
    const user = userEvent.setup();
    render(<Register />);

    await user.type(screen.getByLabelText('Nombre'), 'A');
    await user.type(screen.getByLabelText('Correo electrónico'), 'correo-invalido');
    await user.type(screen.getByLabelText('Contraseña'), 'abc');
    await user.type(screen.getByLabelText('Confirmar contraseña'), 'xyz');
    await user.click(screen.getByRole('button', { name: 'Registrarme' }));

    expect(mockRegister).not.toHaveBeenCalled();
    expect(screen.getByText('El nombre debe tener al menos 2 caracteres.')).toBeInTheDocument();
    expect(screen.getByText('Ingresa un correo válido.')).toBeInTheDocument();
    expect(screen.getByText('Las contraseñas no coinciden.')).toBeInTheDocument();
    expect(screen.getByText(/Añade letras MAYÚSCULAS/i)).toBeInTheDocument();
  });

  it('submits valid form and redirects to home', async () => {
    const user = userEvent.setup();
    mockRegister.mockResolvedValue({ ok: true });

    render(<Register />);

    await user.type(screen.getByLabelText('Nombre'), 'Ana García');
    await user.type(screen.getByLabelText('Correo electrónico'), 'ana@email.com');
    await user.selectOptions(screen.getByLabelText('Rol'), 'cliente');
    await user.type(screen.getByLabelText('Contraseña'), 'Password1');
    await user.type(screen.getByLabelText('Confirmar contraseña'), 'Password1');
    await user.click(screen.getByRole('button', { name: 'Registrarme' }));

    expect(mockRegister).toHaveBeenCalledWith({
      name: 'Ana García',
      email: 'ana@email.com',
      role: 'cliente',
      password: 'Password1',
      confirmPassword: 'Password1',
    });
    expect(mockShowToast).toHaveBeenCalledWith('Cuenta creada correctamente', 'success');
    expect(mockNavigate).toHaveBeenCalledWith('/', { replace: true });
  });
});
